#!/bin/bash
c0="вАЛ";c1="вБ†";case $1 in -01) o="";for((i=0;i<${#2};i++));do b="${2:$i:1}";[ "$b" = "0" ]&&o+="$c0"||[ "$b" = "1" ]&&o+="$c1"||{ echo "–Ґ–Њ–ї—М–Ї–Њ 0 –Є 1.";exit 1;};done;echo "$o" > 01.txt;echo "\"$o\"";;-0f) h="$2";o="";for((i=0;i<${#h};i++));do d=${h:$i:1};val=$((16#$d));for((b=3;b>=0;b--));do (( (val>>b)&1 ))&& o+="$c1"|| o+="$c0";done;done;echo "$o" > 0f.txt;echo "\"$o\"";;-text) o="";for((i=0;i<${#2};i++));do c="${2:$i:1}";printf -v code %d "'$c";for((b=7;b>=0;b--));do (( (code>>b)&1 ))&& o+="$c1"|| o+="$c0";done;done;echo "$o" > text.txt;echo "\"$o\"";;*) echo "–Ш—Б–њ–Њ–ї—М–Ј—Г–є -01, -0f –Є–ї–Є -text";exit 1;;esac
